// Construire URLs de recherche par utilisateur
const profils = $('Supabase - Profils actifs').all();
const prefs = $('Supabase - Pr?f?rences').all();

const cantonToAdzuna = {
  'Vaud': 'vaud', 'Gen?ve': 'geneve', 'Fribourg': 'fribourg',
  'Valais': 'valais', 'Neuch?tel': 'neuchatel', 'Jura': 'jura',
  'Toute la Suisse': '', 'Berne': 'berne', 'Soleure': 'solothurn'
};

const APP_ID = $env['ADZUNA_APP_ID'];
const APP_KEY = $env['ADZUNA_APP_KEY'];
if (!APP_ID || !APP_KEY) throw new Error('ADZUNA credentials not configured in n8n env vars');

const results = [];

for (const profilItem of profils) {
  const profil = profilItem.json;
  // Trouver les pr?f?rences de ce profil
  const prefItem = prefs.find(p => p.json.user_id === profil.id);
  if (!prefItem) continue;
  const pref = prefItem.json;

  const poste = encodeURIComponent(pref.poste_cible || '');
  const localisationRaw = pref.localisation || '';
  const cantons = localisationRaw.split(',').map(c => c.trim());
  const canton = cantons[0] || '';
  const cantonAdzuna = cantonToAdzuna[canton] || '';

  const adzunaUrl = `https://api.adzuna.com/v1/api/jobs/ch/search/1?app_id=${APP_ID}&app_key=${APP_KEY}&what=${poste}&where=${encodeURIComponent(cantonAdzuna)}&results_per_page=20&sort_by=date&content-type=application/json&language=fr`;
  const confUrl = `https://www.jobs.admin.ch/api/v1/jobs/rss?language=fr&query=${poste}`;
  const jobupUrl = `https://www.jobup.ch/fr/jobs/rss/?term=${poste}&region=${encodeURIComponent(canton)}`;

  results.push({
    json: {
      profil_id: profil.id,
      email: profil.email,
      nom: profil.nom,
      plan: profil.plan,
      poste_cible: pref.poste_cible,
      localisation: pref.localisation,
      type_contrat: pref.type_contrat || '',
      annees_exp: profil.cv_texte ? 5 : 0,
      cv_texte: profil.cv_texte || '',
      urls: {
        adzuna: adzunaUrl,
        confederation: confUrl,
        jobup: jobupUrl
      }
    }
  });
}

return results;

