// Helpers RSS/XML parser sans npm
function parseRSSItem(xml, source) {
  const offres = [];
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let itemMatch;
  while ((itemMatch = itemRegex.exec(xml)) !== null) {
    const item = itemMatch[1];
    const getTag = (tag) => {
      const m = item.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>`, 'i'))
             || item.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`, 'i'));
      return m ? m[1].trim() : '';
    };
    const titre = getTag('title');
    const url = getTag('link') || getTag('guid');
    const description = getTag('description').substring(0, 2000);
    const pubDate = getTag('pubDate');
    let entreprise = getTag('author') || getTag('source') || source;
    let localisation = getTag('location') || getTag('georss:point') || '';

    let dateStr = '';
    if (pubDate) {
      try { dateStr = new Date(pubDate).toISOString().split('T')[0]; } catch(e) { dateStr = new Date().toISOString().split('T')[0]; }
    } else {
      dateStr = new Date().toISOString().split('T')[0];
    }

    if (titre && url) {
      offres.push({ source, titre, entreprise, url, localisation, date_publication: dateStr, description });
    }
  }
  return offres;
}

